# ---------------------------------------------------------------------------
# Per-voice empirical words-per-second.
#
# Why this exists: the script-budget calc used a single hardcoded 2.6 wps for
# every voice/language. Sarvam Indian voices render English ad copy at ~1.5–
# 1.85 wps — a 30s ad with a 78-word script (2.6 wps × 30s) became 58s of
# audio. Per-voice WPS sizes the script to the actual rendered duration.
#
# Provider keys: "sarvam:<voice_id>", "google:<voice_name>", "edge:<voice_name>".
# Plain voice ids are also accepted for back-compat (lookup walks all entries).
# Lookup falls back through `provider:voice` → `<any>:voice` → `provider:_default`
# → `2.0` global default.
# ---------------------------------------------------------------------------
_VOICE_WPS: Dict[str, float] = {
    # Sarvam female (en-IN) — measured on 30–90s ad/explainer samples.
    "sarvam:ritu":     1.70,
    "sarvam:priya":    1.65,
    "sarvam:neha":     1.55,
    "sarvam:pooja":    1.55,
    "sarvam:simran":   1.65,
    "sarvam:kavya":    1.70,
    "sarvam:ishita":   1.75,
    "sarvam:shreya":   1.70,
    "sarvam:roopa":    1.60,
    "sarvam:amelia":   2.00,   # English-trained, faster
    "sarvam:sophia":   2.05,
    "sarvam:tanya":    1.85,
    "sarvam:shruti":   1.75,
    "sarvam:suhani":   1.70,
    "sarvam:kavitha":  1.65,
    "sarvam:rupali":   1.70,
    # Sarvam male (en-IN)
    "sarvam:shubh":    1.75,
    "sarvam:aditya":   1.80,
    "sarvam:rahul":    1.85,
    "sarvam:rohan":    1.80,
    "sarvam:amit":     1.80,
    "sarvam:dev":      1.85,
    "sarvam:ratan":    1.75,
    "sarvam:varun":    1.80,
    "sarvam:kabir":    1.75,
    "sarvam:rehan":    1.75,
    "sarvam:soham":    1.80,
    # Provider-tier defaults (used when voice id is unknown)
    "sarvam:_default": 1.75,
    "google:_default": 2.45,   # Google WaveNet/Neural2 — close to legacy 2.6
    "edge:_default":   2.55,   # Edge neural voices — fastest
    "elevenlabs:_default": 2.40,
}


def _resolve_voice_wps(provider: Optional[str], voice_id: Optional[str]) -> float:
    """Return empirical words-per-second for the chosen TTS voice.

    Conservative fallback chain (last resort = 2.0 wps, safer than 2.6 across
    all voices). Used by the script-word-budget calc so a 30s ad doesn't
    produce 78 words for a voice that only speaks 47 in 30s.
    """
    p = (provider or "").strip().lower()
    v = (voice_id or "").strip().lower()
    if p and v:
        wps = _VOICE_WPS.get(f"{p}:{v}")
        if wps:
            return wps
    if v:
        for k, val in _VOICE_WPS.items():
            if k.endswith(f":{v}") and not k.endswith(":_default"):
                return val
    if p:
        d = _VOICE_WPS.get(f"{p}:_default")
        if d:
            return d
    return 2.0


# ── Cheap-model quality engine: pure helpers (best-of-N selection) ───────────
# All pure + side-effect-free → unit-testable without importing the heavy module.
_HIGH_IMPACT_ROLES = {"hook", "cta", "moment", "climax", "payoff"}
_GSAP_TWEEN_RE = re.compile(r"gsap\.(?:to|from|fromTo|set|timeline)\b")
_KEYFRAMES_RE = re.compile(r"@keyframes")
_HTML_TAG_RE = re.compile(r"<[^>]+>")
_COLOR_TOKEN_RE = re.compile(r"var\(--[a-z0-9-]+\)|#[0-9a-fA-F]{3,8}")


def _shot_is_high_impact(shot: Dict[str, Any], shot_idx: int, total_shots: int) -> bool:
    """Should this shot get best-of-N? Highest-impact = hook / CTA / the 'moment'
    payoff / any *_HERO shot / the opener + closer. Pure predicate."""
    if not isinstance(shot, dict):
        return False
    role = (shot.get("intent_role") or "").strip().lower()
    if role in _HIGH_IMPACT_ROLES:
        return True
    if "HERO" in (shot.get("shot_type") or "").upper():
        return True
    if shot_idx == 0 or (total_shots > 1 and shot_idx == total_shots - 1):
        return True
    return False


def _select_best_of_n_shots(shots: List[Dict[str, Any]], max_shots: int, total_shots: int) -> set:
    """The set of shot indices to run best-of-N on, capped at max_shots,
    prioritizing high-impact shots in plan order. Deterministic + pure."""
    if max_shots <= 0 or not shots:
        return set()
    ranked = [i for i, s in enumerate(shots) if _shot_is_high_impact(s, i, total_shots)]
    return set(ranked[:max_shots])


# Phase C — best-of-N composition ANGLES. Each extra candidate commits to one
# distinct angle instead of re-rolling the identical prompt (identical prompts
# at near-identical temperature only ever produced sampling-noise "diversity").
# Angles are picked DETERMINISTICALLY (rotated by shot_index) so resume legs
# regenerate the same candidate set — no RNG in the pipeline.
